  `id` INT PRIMARY KEY DEFAULT 1,
  `aiMode` VARCHAR(50) DEFAULT 'normal',
  `feiraoConfig` TEXT DEFAULT NULL,
  `normalConfig` TEXT DEFAULT NULL,
  `customModes` TEXT DEFAULT NULL,
  `updatedAt` BIGINT DEFAULT NULL
);
INSERT INTO crm_ai_global_config (id, aiMode, feiraoConfig, normalConfig, updatedAt) VALUES (1, 'normal', NULL, NULL, UNIX_TIMESTAMP()*1000) ON DUPLICATE KEY UPDATE id=id;

